Implement the structural fallback renderer - the default rendering when no custom renderer is defined. This is type-aware and budget-respecting.

Location: crates/baml-bridge/src/prompt/renderer.rs

```rust
impl PromptWorld {
    /// Structural (default) renderer - used when no custom renderer defined
    pub fn render_structural(&self, pv: &PromptValue) -> RenderOutput {
        let mut buf = String::new();
        self.render_structural_inner(pv, pv.session.depth, &mut buf);
        RenderOutput { text: buf }
    }

    fn render_structural_inner(&self, pv: &PromptValue, depth: usize, buf: &mut String) {
        let settings = &pv.session.settings;

        // Depth limit
        if depth >= settings.max_depth {
            buf.push_str(&format\!('{} {{ ... }}', self.type_display_name(&pv.ty)));
            return;
        }

        match &pv.value {
            BamlValue::String(s) => {
                // Truncate long strings
                if s.len() > settings.max_string_chars {
                    buf.push_str(&s[..settings.max_string_chars]);
                    buf.push_str('... (truncated)');
                } else {
                    buf.push_str(s);
                }
            }
            BamlValue::Int(i) => buf.push_str(&i.to_string()),
            BamlValue::Float(f) => buf.push_str(&f.to_string()),
            BamlValue::Bool(b) => buf.push_str(if *b { 'true' } else { 'false' }),
            BamlValue::Null => buf.push_str('null'),

            BamlValue::List(items) => {
                self.render_list_structural(pv, items, depth, buf);
            }
            BamlValue::Map(map) => {
                self.render_map_structural(pv, map, depth, buf);
            }
            BamlValue::Class(name, fields) => {
                self.render_class_structural(pv, name, fields, depth, buf);
            }
            BamlValue::Enum(_, variant) => {
                // Use rendered alias if available
                buf.push_str(variant);
            }
            BamlValue::Media(m) => {
                buf.push_str(&format\!('<media: {}>', m.media_type));
            }
        }
    }
}
```

Behavior summary:
- Strings: truncate to max_string_chars
- Lists: show first max_list_items, then '... (+N more)'
- Maps: show first max_map_entries, keys sorted
- Classes: fields in schema order
- Depth: stop at max_depth with 'Type { ... }'
- Unions: if resolved, render as that type; if ambiguous, 'one of: A | B | C'

Implement PromptPath - a lightweight path tracker that builds human-readable strings like 'inputs.history.entries[3].output' for error reporting.

Location: crates/baml-bridge/src/prompt/value.rs

```rust
#[derive(Debug, Clone, Default)]
pub struct PromptPath {
    segments: Vec<PathSegment>,
}

#[derive(Debug, Clone)]
enum PathSegment {
    Field(String),      // .field_name
    Index(usize),       // [0], [1], etc.
    MapKey(String),     // ["key"]
}

impl PromptPath {
    pub fn new() -> Self { Self { segments: vec![] } }

    pub fn push_field(&self, name: impl Into<String>) -> Self {
        let mut new = self.clone();
        new.segments.push(PathSegment::Field(name.into()));
        new
    }

    pub fn push_index(&self, idx: usize) -> Self {
        let mut new = self.clone();
        new.segments.push(PathSegment::Index(idx));
        new
    }

    pub fn push_map_key(&self, key: impl Into<String>) -> Self {
        let mut new = self.clone();
        new.segments.push(PathSegment::MapKey(key.into()));
        new
    }
}

impl std::fmt::Display for PromptPath {
    // Format: inputs.history.entries[3]["key"]
}
```

The path is immutable - push operations return new instances. This allows cheap cloning for child values.
